-- FEPC v14 - Supabase base
create table profiles (id uuid primary key default gen_random_uuid(), employee_number text unique not null, full_name text not null, role text not null, active boolean default true);
create table shifts (id uuid primary key default gen_random_uuid(), profile_id uuid references profiles(id) on delete cascade, work_date date not null, shift_type text not null, manual_125 numeric default 0, manual_1375 numeric default 0, manual_150 numeric default 0);
create table monthly_settings (id uuid primary key default gen_random_uuid(), profile_id uuid references profiles(id) on delete cascade, year int, month int, holidays int default 0, vacation_days int default 1, base_monthly_salary numeric default 1446.51, fixed_supplements numeric default 623.72, base_rate numeric default 9.54, supplement_rate numeric default 13.65, adse_rate numeric default 3.5, ss_rate numeric default 11, irs_rate numeric default 13.53, union_rate numeric default 0.65);
create table payslips (id uuid primary key default gen_random_uuid(), profile_id uuid references profiles(id) on delete cascade, year int, month int, gross_paid numeric default 0, net_paid numeric default 0, overtime_125_paid numeric default 0, overtime_1375_paid numeric default 0, overtime_150_paid numeric default 0, file_url text);
